# providers.tf — configure all three cloud providers in one configuration
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    azurerm = {
      source  = "hashicorp/azurerm"
      version = "~> 3.0"
    }
    google = {
      source  = "hashicorp/google"
      version = "~> 5.0"
    }
  }

  # Store state in S3 (all provider state in a single bucket, separate keys)
  backend "s3" {
    bucket = "my-tf-state-multi-cloud"
    key    = "multi-cloud/terraform.tfstate"
    region = "us-east-1"
  }
}

provider "aws" {
  region = var.aws_region
}

provider "azurerm" {
  features {}
  subscription_id = var.azure_subscription_id
}

provider "google" {
  project = var.gcp_project_id
  region  = var.gcp_region
}

# main.tf — provision resources across three providers in one plan
resource "aws_s3_bucket" "data_lake" {
  bucket = "${var.app_name}-data-lake-${terraform.workspace}"
}

resource "azurerm_resource_group" "rg" {
  name     = "rg-${var.app_name}-${terraform.workspace}"
  location = var.azure_location
}

resource "google_bigquery_dataset" "analytics" {
  dataset_id = "${var.app_name}_analytics"
  location   = var.gcp_region
}

# Cross-cloud output: share S3 ARN for DataSync-like cross-cloud pipelines
output "data_lake_arn" {
  value = aws_s3_bucket.data_lake.arn
}

# Register Entra ID as a SAML IdP in AWS IAM
aws iam create-saml-provider \
  --saml-metadata-document file://azure-ad-metadata.xml \
  --name AzureADSAMLProvider

# Create an IAM role that Entra ID users can assume
cat > trust-policy.json << 'EOF'
{
  "Version": "2012-10-17",
  "Statement": [{
    "Effect": "Allow",
    "Principal": { "Federated": "arn:aws:iam::111122223333:saml-provider/AzureADSAMLProvider" },
    "Action": "sts:AssumeRoleWithSAML",
    "Condition": {
      "StringEquals": {
        "SAML:aud": "https://signin.aws.amazon.com/saml"
      }
    }
  }]
}
EOF

aws iam create-role \
  --role-name AzureAD-Developers \
  --assume-role-policy-document file://trust-policy.json

aws iam attach-role-policy \
  --role-name AzureAD-Developers \
  --policy-arn arn:aws:iam::aws:policy/ReadOnlyAccess
